1	//! Deterministically measure release work backed by committed Formal AI sessions.
2	//!
3	//! Run with `rust-script scripts/self-hosting-metric.rs --since <tag>`. A commit
4	//! is attributed only when it records both of these Git trailers:
5	//!
6	//! - `Formal-AI-Session: <session-id>`
7	//! - `Formal-AI-Evidence: <repo-relative-path>`
8	//!
9	//! The evidence must exist in that commit and contain both `formal-ai` and the
10	//! recorded session id. Changed lines are additions plus deletions reported by
11	//! `git show --numstat`; merge commits and binary files do not contribute.
12	
13	#![allow(dead_code)]
14	
15	use std::env;
16	use std::fs::{self, OpenOptions};
17	use std::io::Write;
18	use std::path::{Component, Path, PathBuf};
19	use std::process::Command;
20	
21	const SESSION_TRAILER: &str = "Formal-AI-Session";
22	const EVIDENCE_TRAILER: &str = "Formal-AI-Evidence";
23	const DEFAULT_LEDGER: &str = "data/meta/self-hosting-ledger.lino";
24	const DEFAULT_TRAILING_WINDOW: usize = 3;
25	
26	#[derive(Clone, Debug, Eq, PartialEq)]
27	pub struct Measurement {
28	    pub self_authored_lines: u64,
29	    pub changed_lines: u64,
30	    pub self_authored_commits: u64,
31	    pub commits: u64,
32	    pub percentage_basis_points: u64,
33	}
34	
35	#[derive(Clone, Debug, Eq, PartialEq)]
36	pub struct ReleaseRow {
37	    pub tag: String,
38	    pub since: String,
39	    pub until: String,
40	    pub self_authored_lines: u64,
41	    pub changed_lines: u64,
42	    pub self_authored_commits: u64,
43	    pub commits: u64,
44	    pub percentage_basis_points: u64,
45	    pub trailing_window: usize,
46	    pub trailing_percentage_basis_points: u64,
47	}
48	
49	pub fn format_percentage(basis_points: u64) -> String {
50	    format!("{}.{:02}%", basis_points / 100, basis_points % 100)
51	}
52	
53	pub fn measure(repo: &Path, since: &str, until: &str) -> Result<Measurement, String> {
54	    let range = format!("{since}..{until}");
55	    let output = git(repo, &["rev-list", "--reverse", "--no-merges", &range])?;
56	    let commits = output
57	        .lines()
58	        .filter(|line| !line.is_empty())
59	        .collect::<Vec<_>>();
60	    let mut changed_lines = 0_u64;
61	    let mut self_authored_lines = 0_u64;
62	    let mut self_authored_commits = 0_u64;
63	
64	    for commit in &commits {
65	        let lines = changed_lines_for_commit(repo, commit)?;
66	        changed_lines = changed_lines
67	            .checked_add(lines)
68	            .ok_or_else(|| "changed-line total overflowed u64".to_owned())?;
69	        if commit_has_formal_ai_evidence(repo, commit)? {
70	            self_authored_lines = self_authored_lines
71	                .checked_add(lines)
72	                .ok_or_else(|| "self-authored line total overflowed u64".to_owned())?;
73	            self_authored_commits += 1;
74	        }
75	    }
76	
77	    Ok(Measurement {
78	        self_authored_lines,
79	        changed_lines,
80	        self_authored_commits,
81	        commits: commits.len() as u64,
82	        percentage_basis_points: percentage_basis_points(self_authored_lines, changed_lines),
83	    })
84	}
85	
86	fn changed_lines_for_commit(repo: &Path, commit: &str) -> Result<u64, String> {
87	    let output = git(
88	        repo,
89	        &["show", "--format=", "--numstat", "--no-renames", commit],
90	    )?;
91	    output.lines().try_fold(0_u64, |total, line| {
92	        let mut fields = line.split('\t');
93	        let additions = fields.next().unwrap_or_default();
94	        let deletions = fields.next().unwrap_or_default();
95	        if additions == "-" || deletions == "-" {
96	            return Ok(total);
97	        }
98	        let additions = additions
99	            .parse::<u64>()
100	            .map_err(|error| format!("invalid numstat additions in {commit}: {error}"))?;
101	        let deletions = deletions
102	            .parse::<u64>()
103	            .map_err(|error| format!("invalid numstat deletions in {commit}: {error}"))?;
104	        total
105	            .checked_add(additions)
106	            .and_then(|sum| sum.checked_add(deletions))
107	            .ok_or_else(|| format!("changed-line count overflowed in {commit}"))
108	    })
109	}
110	
111	fn commit_has_formal_ai_evidence(repo: &Path, commit: &str) -> Result<bool, String> {
112	    let sessions = trailer_values(repo, commit, SESSION_TRAILER)?;
113	    let evidence_paths = trailer_values(repo, commit, EVIDENCE_TRAILER)?;
114	    if sessions.is_empty() && evidence_paths.is_empty() {
115	        return Ok(false);
116	    }
117	    if sessions.is_empty() || evidence_paths.is_empty() {
118	        return Err(format!(
119	            "commit {commit} must record both {SESSION_TRAILER} and {EVIDENCE_TRAILER}"
120	        ));
121	    }
122	
123	    let mut evidence = Vec::with_capacity(evidence_paths.len());
124	    for path in evidence_paths {
125	        validate_evidence_path(&path)?;
126	        let object = format!("{commit}:{path}");
127	        let content = git(repo, &["show", &object])?;
128	        if !content.to_ascii_lowercase().contains("formal-ai") {
129	            return Err(format!(
130	                "evidence {path} in commit {commit} does not identify formal-ai"
131	            ));
132	        }
133	        evidence.push((path, content));
134	    }
135	
136	    for session in sessions {
137	        if !evidence
138	            .iter()
139	            .any(|(_, content)| content.contains(&session))
140	        {
141	            return Err(format!(
142	                "no committed {EVIDENCE_TRAILER} in {commit} records session {session}"
143	            ));
144	        }
145	    }
146	    Ok(true)
147	}
148	
149	fn trailer_values(repo: &Path, commit: &str, key: &str) -> Result<Vec<String>, String> {
150	    let format = format!("%(trailers:key={key},valueonly,separator=%x1f)");
151	    let format_arg = format!("--format={format}");
152	    let output = git(repo, &["show", "-s", &format_arg, commit])?;
153	    Ok(output
154	        .trim()
155	        .split('\x1f')
156	        .map(str::trim)
157	        .filter(|value| !value.is_empty())
158	        .map(str::to_owned)
159	        .collect())
160	}
161	
162	fn validate_evidence_path(path: &str) -> Result<(), String> {
163	    let candidate = Path::new(path);
164	    if path.contains(':')
165	        || path.contains('\n')
166	        || candidate.is_absolute()
167	        || candidate
168	            .components()
169	            .any(|component| !matches!(component, Component::Normal(_)))
170	    {
171	        return Err(format!(
172	            "{EVIDENCE_TRAILER} must be a normal repo-relative path: {path}"
173	        ));
174	    }
175	    Ok(())
176	}
177	
178	fn percentage_basis_points(numerator: u64, denominator: u64) -> u64 {
179	    if denominator == 0 {
180	        return 0;
181	    }
182	    let rounded =
183	        (u128::from(numerator) * 10_000 + u128::from(denominator) / 2) / u128::from(denominator);
184	    u64::try_from(rounded).expect("percentage basis points fit in u64")
185	}
186	
187	pub fn record_release(
188	    repo: &Path,
189	    ledger: &Path,
190	    tag: &str,
191	    since: &str,
192	    until: &str,
193	    trailing_window: usize,
194	) -> Result<ReleaseRow, String> {
195	    if trailing_window == 0 {
196	        return Err("trailing window must be greater than zero".to_owned());
197	    }
198	    let rows = read_release_rows(ledger)?;
199	    let measurement = measure(repo, since, until)?;
200	    let until_commitish = format!("{until}^{{commit}}");
201	    let canonical_until = git(repo, &["rev-parse", &until_commitish])?
202	        .trim()
203	        .to_owned();
204	    let mut window_rows = rows
205	        .iter()
206	        .rev()
207	        .take(trailing_window.saturating_sub(1))
208	        .cloned()
209	        .collect::<Vec<_>>();
210	    window_rows.reverse();
211	    let mut row = ReleaseRow {
212	        tag: tag.to_owned(),
213	        since: since.to_owned(),
214	        until: canonical_until,
215	        self_authored_lines: measurement.self_authored_lines,
216	        changed_lines: measurement.changed_lines,

